#!/usr/bin/env python3
# handoff_check.py — validates handoff checklist is complete before rotation
import os
import sys
import requests
from datetime import datetime, timedelta, timezone

PROMETHEUS_URL = os.environ['PROMETHEUS_URL']
JIRA_URL       = os.environ['JIRA_URL']
JIRA_TOKEN     = os.environ['JIRA_TOKEN']

def check_budget_status() -> tuple[bool, str]:
    query = 'min(slo:error_budget:remaining)'
    resp = requests.get(
        f'{PROMETHEUS_URL}/api/v1/query',
        params={'query': query},
        timeout=5,
    )
    result = resp.json()['data']['result']
    if not result:
        return False, 'Could not fetch budget status'
    remaining = float(result[0]['value'][1])
    if remaining < 0.20:
        return False, (
            f'Budget below 20% ({remaining:.1%}). '
            'Incoming on-call must explicitly acknowledge freeze watch.'
        )
    return True, f'Budget healthy: {remaining:.1%} remaining'

def check_open_incidents() -> tuple[bool, str]:
    resp = requests.get(
        f'{JIRA_URL}/rest/api/3/search',
        params={
            'jql': 'project=OPS AND status in ("In Progress","Open") AND priority in (P1,P2)',
            'fields': 'summary,priority,assignee',
            'maxResults': 10,
        },
        headers={'Authorization': f'Bearer {JIRA_TOKEN}'},
        timeout=10,
    )
    issues = resp.json().get('issues', [])
    if issues:
        summaries = [i['fields']['summary'] for i in issues]
        return False, (
            f'{len(issues)} open P1/P2 incident(s):\n'
            + '\n'.join(f'  • {s}' for s in summaries)
            + '\nSynchronous handoff required for active incidents.'
        )
    return True, 'No open P1/P2 incidents'

if __name__ == '__main__':
    checks = [
        ('Budget status', check_budget_status),
        ('Open incidents', check_open_incidents),
    ]
    failed = False
    for name, fn in checks:
        ok, msg = fn()
        status = 'OK  ' if ok else 'WARN'
        print(f'[{status}] {name}: {msg}')
        if not ok:
            failed = True
    sys.exit(1 if failed else 0)

# oncall_metrics.py — tracks on-call health metrics for toil reduction
from dataclasses import dataclass, field
from datetime import datetime
from collections import defaultdict

@dataclass
class OncallWeek:
    engineer: str
    week_start: datetime
    alerts_paged: int = 0
    incidents_p1: int = 0
    incidents_p2: int = 0
    interruptions_off_hours: int = 0  # pages between 22:00 and 08:00 local
    runbook_gaps_found: int = 0       # times no runbook existed for an alert
    toil_hours_estimated: float = 0.0

@dataclass
class OncallHealthReport:
    weeks: list[OncallWeek] = field(default_factory=list)

    @property
    def avg_alerts_per_week(self) -> float:
        if not self.weeks:
            return 0.0
        return sum(w.alerts_paged for w in self.weeks) / len(self.weeks)

    @property
    def avg_off_hours_interruptions(self) -> float:
        if not self.weeks:
            return 0.0
        return sum(w.interruptions_off_hours for w in self.weeks) / len(self.weeks)

    def toil_threshold_exceeded(self) -> bool:
        # Google SRE target: on-call toil < 50% of engineer's time
        # Approximate: > 8 off-hours interruptions/week is unsustainable
        return self.avg_off_hours_interruptions > 8

    def runbook_gap_rate(self) -> float:
        total_alerts = sum(w.alerts_paged for w in self.weeks)
        total_gaps   = sum(w.runbook_gaps_found for w in self.weeks)
        return total_gaps / total_alerts if total_alerts > 0 else 0.0
